#include <EEPROM.h>
#define SN 0
#define SD 1
#define SI 2
#define SR 3
static uint8_t li=0;
uint8_t fsm_transition(uint8_t s,uint8_t ev,uint8_t fc){
  uint8_t ns=s;
  if(s==SN&&ev==1)ns=SD;
  else if(s==SD&&ev==2)ns=SI;
  else if(s==SI&&ev==3)ns=SR;
  else if(s==SR&&ev==0)ns=SN;
  if(ns!=s){
    EEPROM.write(li*4,s);
    EEPROM.write(li*4+1,ns);
    EEPROM.write(li*4+2,fc);
    EEPROM.write(li*4+3,(uint8_t)(millis()>>8));
    li=(li+1)%16;}
  return ns;
}
